// ================= Models =================
model Category {
    integer id primary;
    string name unique;
    string description nullable;

    hasMany Book;
}

model Publisher {
    integer id primary;
    string name unique;
    string address nullable;
    string phone nullable;

    hasMany Book;
}

model Author {
    integer id primary;
    string name;
    text biography nullable;
    date birthDate nullable;

    belongsToMany Book;
}

model Book {
    integer id primary;
    string title;
    string isbn unique;
    integer year;
    integer Category_id;
    integer Publisher_id;
    boolean available default(true);

    belongsTo Category;
    belongsTo Publisher;
    belongsToMany Author;
    hasMany BorrowRecord;
    hasMany Reservation;
}

model AuthorBook {
    integer id primary;
    integer Book_id;
    integer Author_id;

    belongsTo Book;
    belongsTo Author;
}

model Member {
    integer id primary;
    string name;
    string email unique;
    string phone nullable;
    date membershipDate;
    string status default("active");

    hasMany BorrowRecord;
    hasMany Reservation;
    hasMany Fine;
}

model BorrowRecord {
    integer id primary;
    integer Book_id;
    integer Member_id;
    datetime borrowedAt;
    datetime dueDate;
    datetime returnedAt nullable;

    belongsTo Book;
    belongsTo Member;
    hasOne Fine;
}

model Reservation {
    integer id primary;
    integer Book_id;
    integer Member_id;
    datetime reservedAt;
    string status default("pending");

    belongsTo Book;
    belongsTo Member;
}

model Fine {
    integer id primary;
    integer BorrowRecord_id;
    integer Member_id;
    decimal amount;
    boolean isPaid default(false);

    belongsTo BorrowRecord;
    belongsTo Member;
}

// ================= Controllers =================
controller CategoryController {
    function listCategoriesAction(Request req) {
        var cats = Category.modelFindAll();
